console.log('1. Script starts');

// Hand-off to browser's network Web API
fetch('https://api.example.com/data')
  .then(res => res.json())            // runs when network responds
  .then(data => {
    console.log('4. Data arrived:', data); // runs via Event Loop
  });

setTimeout(() => {
  console.log('3. Timer fired');       // runs via Event Loop after network
}, 0);

console.log('2. Script continues');

// Output:
// 1. Script starts
// 2. Script continues
// 3. Timer fired         ← macrotask
// 4. Data arrived: ...  ← microtask (Promise), but after network I/O

