// Nested setTimeout — browser enforces minimum 4ms after 5 levels
function nested(depth) {
  if (depth >= 5) {
    console.log('Browser now enforces 4ms minimum');
    return;
  }
  setTimeout(() => nested(depth + 1), 0);
}
nested(0);
